import{_ as e,c as t,o as n,a as s}from"./app.1d1a677f.js";const g=JSON.parse('{"title":"\u{1F680} Getting Started with UniTrack","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u{1F4CB} Prerequisites","slug":"\u{1F4CB}-prerequisites","link":"#\u{1F4CB}-prerequisites","children":[]},{"level":2,"title":"\u{1F6E0}\uFE0F Setup Options","slug":"\u{1F6E0}\uFE0F-setup-options","link":"#\u{1F6E0}\uFE0F-setup-options","children":[]},{"level":2,"title":"\u{1F3C1} Quick Start","slug":"\u{1F3C1}-quick-start","link":"#\u{1F3C1}-quick-start","children":[]},{"level":2,"title":"\u{1F504} System Requirements","slug":"\u{1F504}-system-requirements","link":"#\u{1F504}-system-requirements","children":[]},{"level":2,"title":"\u{1F4DA} Documentation Structure","slug":"\u{1F4DA}-documentation-structure","link":"#\u{1F4DA}-documentation-structure","children":[]},{"level":2,"title":"\u26A0\uFE0F Important Notes","slug":"\u26A0\uFE0F-important-notes","link":"#\u26A0\uFE0F-important-notes","children":[]}],"relativePath":"bg/setup/getting-started.md","lastUpdated":1744658590000}'),r={name:"bg/setup/getting-started.md"},o=s(`<h1 id="\u{1F680}-getting-started-with-unitrack" tabindex="-1">\u{1F680} Getting Started with UniTrack <a class="header-anchor" href="#\u{1F680}-getting-started-with-unitrack" aria-hidden="true">#</a></h1><p>Welcome to the setup guide for UniTrack, a comprehensive university management system. This guide will walk you through the installation and configuration process to get your instance up and running.</p><h2 id="\u{1F4CB}-prerequisites" tabindex="-1">\u{1F4CB} Prerequisites <a class="header-anchor" href="#\u{1F4CB}-prerequisites" aria-hidden="true">#</a></h2><p>Before you begin, make sure you have the following installed on your system:</p><ul><li><strong>Docker</strong> (version 20.10.0 or later)</li><li><strong>Docker Compose</strong> (version 2.0.0 or later)</li><li><strong>Git</strong> (for cloning the repository)</li><li><strong>Bash shell</strong> (for running the deployment scripts)</li></ul><h2 id="\u{1F6E0}\uFE0F-setup-options" tabindex="-1">\u{1F6E0}\uFE0F Setup Options <a class="header-anchor" href="#\u{1F6E0}\uFE0F-setup-options" aria-hidden="true">#</a></h2><p>UniTrack offers several setup options depending on your needs:</p><ol><li><strong><a href="/en/setup/deployment-dev.html">Docker Development Setup</a></strong> - Quick setup for local development</li><li><strong><a href="/en/setup/deployment-prod.html">Docker Production Setup</a></strong> - Full production deployment with Docker Swarm</li></ol><h2 id="\u{1F3C1}-quick-start" tabindex="-1">\u{1F3C1} Quick Start <a class="header-anchor" href="#\u{1F3C1}-quick-start" aria-hidden="true">#</a></h2><p>For the quickest possible setup, follow these steps:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;"># Clone the repository</span></span>
<span class="line"><span style="color:#A6ACCD;">git clone https://github.com/SpasMilenkov/UniTrackRemaster.git</span></span>
<span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> UniTrackRemaster</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;"># Start the development environment</span></span>
<span class="line"><span style="color:#A6ACCD;">docker-compose -f docker-compose.dev.yml up</span></span>
<span class="line"></span></code></pre></div><p>This will start a simplified development environment with:</p><ul><li>PostgreSQL database</li><li>Backend API</li><li>Frontend application</li></ul><p>Access the application at <a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a></p><h2 id="\u{1F504}-system-requirements" tabindex="-1">\u{1F504} System Requirements <a class="header-anchor" href="#\u{1F504}-system-requirements" aria-hidden="true">#</a></h2><p>UniTrack is designed to be lightweight, but for optimal performance we recommend:</p><table><thead><tr><th>Component</th><th>Minimum</th><th>Recommended</th></tr></thead><tbody><tr><td>CPU</td><td>2 cores</td><td>4+ cores</td></tr><tr><td>RAM</td><td>4GB</td><td>8GB+</td></tr><tr><td>Storage</td><td>10GB</td><td>20GB+</td></tr><tr><td>Network</td><td>10Mbps</td><td>100Mbps+</td></tr></tbody></table><h2 id="\u{1F4DA}-documentation-structure" tabindex="-1">\u{1F4DA} Documentation Structure <a class="header-anchor" href="#\u{1F4DA}-documentation-structure" aria-hidden="true">#</a></h2><p>The complete setup documentation is organized as follows:</p><ul><li><strong><a href="/en/setup/deployment-dev.html">Docker Development Setup</a></strong> - For local development</li><li><strong><a href="/en/setup/deployment-prod.html">Docker Production Setup</a></strong> - For production environments</li><li><strong><a href="/en/setup/config.html">Configuration Options</a></strong> - Details on all configuration parameters</li><li><strong><a href="/en/setup/troubleshooting.html">Troubleshooting</a></strong> - Common issues and solutions</li></ul><h2 id="\u26A0\uFE0F-important-notes" tabindex="-1">\u26A0\uFE0F Important Notes <a class="header-anchor" href="#\u26A0\uFE0F-important-notes" aria-hidden="true">#</a></h2><ul><li>Default database credentials should be changed before exposing the system to the internet</li><li>For educational institutions, we recommend starting with a test deployment before migrating to production</li><li>Firebase credentials are required for certain features like notifications</li></ul><p>Next, proceed to the <a href="/en/setup/deployment-prod.html">Docker Production Setup</a> to learn about setting up UniTrack in a production environment.</p>`,23),i=[o];function a(l,p,d,c,u,h){return n(),t("div",null,i)}const f=e(r,[["render",a]]);export{g as __pageData,f as default};
